#include "streamcluster_header.cu"

using namespace std;

// Global variables
bool *switch_membership;
bool* is_center;
int* center_table;
float* block;
int nproc;
int c, d;

#ifdef PROFILE
double time_local_search;
double time_speedy;
double time_select_feasible;
double time_gain;
double time_shuffle;
double time_gain_dist;
double time_gain_init;
#endif

// CUDA device pointers (global for reuse)
static float  *d_coord           = NULL;
static int    *d_center_table    = NULL;
static bool   *d_switch_membership = NULL;
static bool   *d_is_center       = NULL;
static float  *d_p_cost          = NULL;
static float  *d_p_weight        = NULL;
static long   *d_p_assign        = NULL;

static long d_num_allocated = 0;
static int  d_dim_allocated = 0;

// -----------------------------------------------------------------------
// Helper
// -----------------------------------------------------------------------
double gettime() {
  struct timeval t;
  gettimeofday(&t, NULL);
  return (double)t.tv_sec + t.tv_usec*1e-6;
}

float dist(Point p1, Point p2, int dim) {
  int i;
  float result = 0.0f;
  for (i = 0; i < dim; i++)
    result += (p1.coord[i] - p2.coord[i])*(p1.coord[i] - p2.coord[i]);
  return result;
}

static int floatcomp(const void *i, const void *j) {
  float a = *(float *)(i);
  float b = *(float *)(j);
  if (a > b) return  1;
  if (a < b) return -1;
  return 0;
}

void shuffle(Points *points) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  Point temp;
  for (i = 0; i < points->num-1; i++) {
    j = (lrand48()%(points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2-t1;
#endif
}

void intshuffle(int *intarray, int length) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  int temp;
  for (i = 0; i < length; i++) {
    j = (lrand48()%(length - i)) + i;
    temp = intarray[i];
    intarray[i] = intarray[j];
    intarray[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2-t1;
#endif
}

// -----------------------------------------------------------------------
// CUDA kernels
// -----------------------------------------------------------------------

// Main distance kernel: for each point i compute x_cost vs current_cost,
// set switch_membership, accumulate into d_lower (atomicAdd), and store
// per-point cost delta into d_cost_arr.
__global__ void pgain_kernel(
    int   num,
    int   dim,
    long  x,
    float  *d_coord,
    float  *d_p_cost,
    float  *d_p_weight,
    long   *d_p_assign,
    int    *d_center_table,
    bool   *d_is_center,
    bool   *d_switch_membership,
    double *d_lower,
    double *d_cost_arr
) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= num) return;

    float x_cost = 0.0f;
    for (int k = 0; k < dim; k++) {
        float diff = d_coord[i*dim + k] - d_coord[x*dim + k];
        x_cost += diff * diff;
    }
    x_cost *= d_p_weight[i];
    float current_cost = d_p_cost[i];

    if (x_cost < current_cost) {
        d_switch_membership[i] = 1;
        d_cost_arr[i] = (double)(x_cost - current_cost);
    } else {
        d_switch_membership[i] = 0;
        d_cost_arr[i] = 0.0;
        int assign = (int)d_p_assign[i];
        atomicAdd(&d_lower[d_center_table[assign]], (double)(current_cost - x_cost));
    }
}

// Reduction kernel
__global__ void reduce_sum_kernel(double *d_in, double *d_out, int n) {
    extern __shared__ double sdata[];
    int tid = threadIdx.x;
    int i   = blockIdx.x * blockDim.x + threadIdx.x;
    sdata[tid] = (i < n) ? d_in[i] : 0.0;
    __syncthreads();
    for (int s = blockDim.x/2; s > 0; s >>= 1) {
        if (tid < s) sdata[tid] += sdata[tid + s];
        __syncthreads();
    }
    if (tid == 0) d_out[blockIdx.x] = sdata[0];
}

// Update assignments after deciding to open x
__global__ void pgain_update_kernel(
    int    num,
    int    dim,
    long   x,
    float  *d_coord,
    float  *d_p_cost,
    float  *d_p_weight,
    long   *d_p_assign,
    int    *d_center_table,
    bool   *d_switch_membership,
    double *d_gl_lower
) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= num) return;

    bool close_center = d_gl_lower[d_center_table[(int)d_p_assign[i]]] > 0;
    if (d_switch_membership[i] || close_center) {
        float cost = 0.0f;
        for (int k = 0; k < dim; k++) {
            float diff = d_coord[i*dim + k] - d_coord[x*dim + k];
            cost += diff * diff;
        }
        d_p_cost[i]   = d_p_weight[i] * cost;
        d_p_assign[i] = x;
    }
}

// Close centers whose gl_lower > 0
__global__ void pgain_close_centers_kernel(
    int    num,
    bool   *d_is_center,
    int    *d_center_table,
    double *d_gl_lower
) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= num) return;
    if (d_is_center[i] && d_gl_lower[d_center_table[i]] > 0) {
        d_is_center[i] = false;
    }
}

// -----------------------------------------------------------------------
// GPU-accelerated pgain implementation
// -----------------------------------------------------------------------
static double pgain_cuda_impl(long x, Points *points, double z, long int *numcenters) {
#ifdef PROFILE
    double t0 = gettime();
#endif

    long num = points->num;
    int  dim = points->dim;

    // Build center_table on CPU
    int count = 0;
    for (int i = 0; i < num; i++) {
        if (is_center[i]) {
            center_table[i] = count++;
        }
    }
    int K = (int)(*numcenters);

    // (Re)allocate device memory if needed
    if (num > d_num_allocated || dim > d_dim_allocated) {
        if (d_coord)             cudaFree(d_coord);
        if (d_center_table)      cudaFree(d_center_table);
        if (d_switch_membership) cudaFree(d_switch_membership);
        if (d_is_center)         cudaFree(d_is_center);
        if (d_p_cost)            cudaFree(d_p_cost);
        if (d_p_weight)          cudaFree(d_p_weight);
        if (d_p_assign)          cudaFree(d_p_assign);

        cudaMalloc(&d_coord,             (size_t)num * dim * sizeof(float));
        cudaMalloc(&d_center_table,      (size_t)num * sizeof(int));
        cudaMalloc(&d_switch_membership, (size_t)num * sizeof(bool));
        cudaMalloc(&d_is_center,         (size_t)num * sizeof(bool));
        cudaMalloc(&d_p_cost,            (size_t)num * sizeof(float));
        cudaMalloc(&d_p_weight,          (size_t)num * sizeof(float));
        cudaMalloc(&d_p_assign,          (size_t)num * sizeof(long));

        d_num_allocated = num;
        d_dim_allocated = dim;
    }

    // Per-call device allocations
    double *d_lower    = NULL;
    double *d_cost_arr = NULL;

    int numBlocks = (int)((num + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK);
    double *d_block_out = NULL;

    cudaMalloc(&d_lower,    (size_t)(K + 1) * sizeof(double));
    cudaMalloc(&d_cost_arr, (size_t)num      * sizeof(double));
    cudaMalloc(&d_block_out,(size_t)numBlocks * sizeof(double));

    // Pack coordinates into flat array and upload
    float *h_coord = (float*)malloc((size_t)num * dim * sizeof(float));
    for (int i = 0; i < num; i++)
        memcpy(h_coord + i*dim, points->p[i].coord, dim * sizeof(float));
    cudaMemcpy(d_coord, h_coord, (size_t)num * dim * sizeof(float), cudaMemcpyHostToDevice);
    free(h_coord);

    // Upload per-point arrays
    float *h_cost   = (float*)malloc((size_t)num * sizeof(float));
    float *h_weight = (float*)malloc((size_t)num * sizeof(float));
    long  *h_assign = (long* )malloc((size_t)num * sizeof(long));
    for (int i = 0; i < num; i++) {
        h_cost[i]   = points->p[i].cost;
        h_weight[i] = points->p[i].weight;
        h_assign[i] = points->p[i].assign;
    }
    cudaMemcpy(d_p_cost,   h_cost,   (size_t)num * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_p_weight, h_weight, (size_t)num * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_p_assign, h_assign, (size_t)num * sizeof(long),  cudaMemcpyHostToDevice);

    cudaMemcpy(d_center_table,      center_table,      (size_t)num * sizeof(int),  cudaMemcpyHostToDevice);
    cudaMemcpy(d_is_center,         is_center,         (size_t)num * sizeof(bool), cudaMemcpyHostToDevice);
    cudaMemcpy(d_switch_membership, switch_membership, (size_t)num * sizeof(bool), cudaMemcpyHostToDevice);

    cudaMemset(d_lower,    0, (size_t)(K + 1) * sizeof(double));
    cudaMemset(d_cost_arr, 0, (size_t)num      * sizeof(double));

#ifdef PROFILE
    double t1 = gettime();
    time_gain_init += t1 - t0;
#endif

    // Launch main kernel
    pgain_kernel<<<numBlocks, THREADS_PER_BLOCK>>>(
        (int)num, dim, x,
        d_coord, d_p_cost, d_p_weight, d_p_assign,
        d_center_table, d_is_center,
        d_switch_membership,
        d_lower,
        d_cost_arr
    );
    cudaDeviceSynchronize();

#ifdef PROFILE
    double t2 = gettime();
    time_gain_dist += t2 - t1;
#endif

    // Reduce d_cost_arr on GPU (multi-level)
    {
        double *src = d_cost_arr;
        double *dst = d_block_out;
        int n = (int)num;
        while (n > 1) {
            int nb = (n + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK;
            reduce_sum_kernel<<<nb, THREADS_PER_BLOCK,
                                THREADS_PER_BLOCK*sizeof(double)>>>(src, dst, n);
            cudaDeviceSynchronize();
            // swap src/dst using d_cost_arr as scratch
            if (nb > 1) {
                cudaMemcpy(d_cost_arr, dst, nb * sizeof(double), cudaMemcpyDeviceToDevice);
                src = d_cost_arr;
                dst = d_block_out;
            }
            n = nb;
        }
    }
    double cost_partial = 0.0;
    cudaMemcpy(&cost_partial, d_block_out, sizeof(double), cudaMemcpyDeviceToHost);

    // Copy lower back to CPU
    double *h_lower = (double*)malloc((size_t)(K + 1) * sizeof(double));
    cudaMemcpy(h_lower, d_lower, (size_t)(K + 1) * sizeof(double), cudaMemcpyDeviceToHost);

    // Compute gl_lower and number_of_centers_to_close on CPU
    double *gl_lower = (double*)calloc(K + 1, sizeof(double));
    int    number_of_centers_to_close = 0;
    double cost_of_opening_x = cost_partial;

    for (int i = 0; i < num; i++) {
        if (is_center[i]) {
            double low = z + h_lower[center_table[i]];
            gl_lower[center_table[i]] = low;
            if (low > 0) {
                number_of_centers_to_close++;
                cost_of_opening_x -= low;
            }
        }
    }

    double gl_cost_of_opening_x = z + cost_of_opening_x;

    if (gl_cost_of_opening_x < 0) {
        // Upload gl_lower and run update kernels
        cudaMemcpy(d_lower, gl_lower, (size_t)(K + 1) * sizeof(double), cudaMemcpyHostToDevice);

        pgain_update_kernel<<<numBlocks, THREADS_PER_BLOCK>>>(
            (int)num, dim, x,
            d_coord, d_p_cost, d_p_weight, d_p_assign,
            d_center_table,
            d_switch_membership,
            d_lower
        );
        cudaDeviceSynchronize();

        pgain_close_centers_kernel<<<numBlocks, THREADS_PER_BLOCK>>>(
            (int)num, d_is_center, d_center_table, d_lower
        );
        cudaDeviceSynchronize();

        // Copy results back to host
        cudaMemcpy(h_cost,   d_p_cost,   (size_t)num * sizeof(float), cudaMemcpyDeviceToHost);
        cudaMemcpy(h_assign, d_p_assign, (size_t)num * sizeof(long),  cudaMemcpyDeviceToHost);
        cudaMemcpy(is_center,         d_is_center,         (size_t)num * sizeof(bool), cudaMemcpyDeviceToHost);
        cudaMemcpy(switch_membership, d_switch_membership, (size_t)num * sizeof(bool), cudaMemcpyDeviceToHost);

        for (int i = 0; i < num; i++) {
            points->p[i].cost   = h_cost[i];
            points->p[i].assign = h_assign[i];
        }

        is_center[x] = true;
        *numcenters = *numcenters + 1 - number_of_centers_to_close;
    } else {
        gl_cost_of_opening_x = 0.0;
    }

    free(h_lower);
    free(gl_lower);
    free(h_cost);
    free(h_weight);
    free(h_assign);
    cudaFree(d_lower);
    cudaFree(d_cost_arr);
    cudaFree(d_block_out);

#ifdef PROFILE
    double t3 = gettime();
    time_gain += t3 - t0;
#endif

    return -gl_cost_of_opening_x;
}

// -----------------------------------------------------------------------
// pspeedy  (single-threaded, nproc==1)
// -----------------------------------------------------------------------
float pspeedy(Points *points, float z, long *kcenter, int pid, pthread_barrier_t* barrier) {
#ifdef PROFILE
    double t1 = gettime();
#endif

    long bsize = points->num / nproc;
    long k1    = bsize * pid;
    long k2    = k1 + bsize;
    if (pid == nproc-1) k2 = points->num;

    static double  totalcost;
    static double *costs;

    // Initialise every point to be assigned to point 0
    for (int k = k1; k < k2; k++) {
        float distance = dist(points->p[k], points->p[0], points->dim);
        points->p[k].cost   = distance * points->p[k].weight;
        points->p[k].assign = 0;
    }

    if (pid == 0) {
        *kcenter = 1;
        costs    = (double*)malloc(sizeof(double)*nproc);
    }

    // Master thread decides which centers to open
    if (pid == 0) {
        for (int i = 1; i < points->num; i++) {
            bool to_open = ((float)lrand48()/(float)INT_MAX) < (points->p[i].cost / z);
            if (to_open) {
                (*kcenter)++;
                for (int k = k1; k < k2; k++) {
                    float distance = dist(points->p[i], points->p[k], points->dim);
                    if (distance * points->p[k].weight < points->p[k].cost) {
                        points->p[k].cost   = distance * points->p[k].weight;
                        points->p[k].assign = i;
                    }
                }
            }
        }
    }

    double mytotal = 0;
    for (int k = k1; k < k2; k++)
        mytotal += points->p[k].cost;
    costs[pid] = mytotal;

    if (pid == 0) {
        totalcost = z * (*kcenter);
        for (int i = 0; i < nproc; i++)
            totalcost += costs[i];
        free(costs);
    }

#ifdef PROFILE
    double t2 = gettime();
    if (pid == 0) time_speedy += t2 - t1;
#endif
    return (float)totalcost;
}

// -----------------------------------------------------------------------
// pgain  (dispatches to CUDA implementation)
// -----------------------------------------------------------------------
double pgain(long x, Points *points, double z, long int *numcenters,
             int pid, pthread_barrier_t* barrier) {
    return pgain_cuda_impl(x, points, z, numcenters);
}

// -----------------------------------------------------------------------
// pFL
// -----------------------------------------------------------------------
float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, double cost, long iter, float e,
          int pid, pthread_barrier_t* barrier) {
    long i, x;
    double change = cost;

    while (change/cost > 1.0*e) {
        change = 0.0;
        if (pid == 0)
            intshuffle(feasible, numfeasible);
        for (i = 0; i < iter; i++) {
            x = i % numfeasible;
            change += pgain(feasible[x], points, z, k, pid, barrier);
            c++;
        }
        cost -= change;
    }
    return (float)cost;
}

// -----------------------------------------------------------------------
// selectfeasible_fast
// -----------------------------------------------------------------------
int selectfeasible_fast(Points *points, int **feasible, int kmin,
                        int pid, pthread_barrier_t* barrier) {
#ifdef PROFILE
    double t1 = gettime();
#endif

    int numfeasible = points->num;
    if (numfeasible > (ITER*kmin*log((double)kmin)))
        numfeasible = (int)(ITER*kmin*log((double)kmin));
    *feasible = (int *)malloc(numfeasible*sizeof(int));

    long k1 = 0;
    long k2 = numfeasible;

    if (numfeasible == points->num) {
        for (int i = k1; i < k2; i++)
            (*feasible)[i] = i;
        return numfeasible;
    }

    float *accumweight = (float*)malloc(sizeof(float)*points->num);
    accumweight[0] = points->p[0].weight;
    for (int i = 1; i < points->num; i++)
        accumweight[i] = accumweight[i-1] + points->p[i].weight;
    float totalweight = accumweight[points->num-1];

    for (int i = k1; i < k2; i++) {
        float w = (lrand48()/(float)INT_MAX)*totalweight;
        int l = 0, r = points->num-1, k;
        if (accumweight[0] > w) { (*feasible)[i] = 0; continue; }
        while (l+1 < r) {
            k = (l+r)/2;
            if (accumweight[k] > w) r = k;
            else                    l = k;
        }
        (*feasible)[i] = r;
    }
    free(accumweight);

#ifdef PROFILE
    double t2 = gettime();
    time_select_feasible += t2-t1;
#endif
    return numfeasible;
}

// -----------------------------------------------------------------------
// pkmedian
// -----------------------------------------------------------------------
float pkmedian(Points *points, long kmin, long kmax, long *kfinal,
               int pid, pthread_barrier_t* barrier) {
    int i;
    double cost, lastcost, hiz, loz, z;

    static long  k;
    static int  *feasible;
    static int   numfeasible;
    static double *hizs;

    if (pid == 0) hizs = (double*)calloc(nproc, sizeof(double));
    hiz = loz = 0.0;
    long ptDimension = points->dim;

    long bsize = points->num / nproc;
    long k1    = bsize * pid;
    long k2    = k1 + bsize;
    if (pid == nproc-1) k2 = points->num;

    double myhiz = 0;
    for (long kk = k1; kk < k2; kk++)
        myhiz += dist(points->p[kk], points->p[0], ptDimension) * points->p[kk].weight;
    hizs[pid] = myhiz;

    for (int i = 0; i < nproc; i++)
        hiz += hizs[i];

    loz = 0.0; z = (hiz+loz)/2.0;

    if (points->num <= kmax) {
        for (long kk = k1; kk < k2; kk++) {
            points->p[kk].assign = kk;
            points->p[kk].cost   = 0;
        }
        cost = 0;
        if (pid == 0) { free(hizs); *kfinal = k; }
        return (float)cost;
    }

    if (pid == 0) shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);

    i = 0;
    while ((k < kmin) && (i < SP)) {
        cost = pspeedy(points, z, &k, pid, barrier);
        i++;
    }

    while (k < kmin) {
        if (i >= SP) { hiz = z; z = (hiz+loz)/2.0; i = 0; }
        if (pid == 0) shuffle(points);
        cost = pspeedy(points, z, &k, pid, barrier);
        i++;
    }

    if (pid == 0) {
        numfeasible = selectfeasible_fast(points, &feasible, kmin, pid, barrier);
        for (int i = 0; i < points->num; i++)
            is_center[points->p[i].assign] = true;
    }

    while (1) {
        d++;
        lastcost = cost;
        cost = pFL(points, feasible, numfeasible,
                   z, &k, cost, (long)(ITER*kmax*log((double)kmax)), 0.1f, pid, barrier);

        if (((k <= (1.1)*kmax) && (k >= (0.9)*kmin)) ||
            ((k <= kmax+2)     && (k >= kmin-2))) {
            cost = pFL(points, feasible, numfeasible,
                       z, &k, cost, (long)(ITER*kmax*log((double)kmax)), 0.001f, pid, barrier);
        }

        if (k > kmax) { loz = z; z = (hiz+loz)/2.0; cost += (z-loz)*k; }
        if (k < kmin) { hiz = z; z = (hiz+loz)/2.0; cost += (z-hiz)*k; }

        if (((k <= kmax) && (k >= kmin)) || (loz >= (0.999)*hiz))
            break;
    }

    if (pid == 0) { free(feasible); free(hizs); *kfinal = k; }
    return (float)cost;
}

// -----------------------------------------------------------------------
// contcenters / copycenters / outcenterIDs
// -----------------------------------------------------------------------
int contcenters(Points *points) {
    long i, ii;
    float relweight;
    for (i = 0; i < points->num; i++) {
        if (points->p[i].assign != i) {
            relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
            relweight = points->p[i].weight / relweight;
            for (ii = 0; ii < points->dim; ii++) {
                points->p[points->p[i].assign].coord[ii] *= 1.0f - relweight;
                points->p[points->p[i].assign].coord[ii] += points->p[i].coord[ii] * relweight;
            }
            points->p[points->p[i].assign].weight += points->p[i].weight;
        }
    }
    return 0;
}

void copycenters(Points *points, Points *centers, long *centerIDs, long offset) {
    long i, k;
    bool *is_a_median = (bool *)calloc(points->num, sizeof(bool));
    for (i = 0; i < points->num; i++)
        is_a_median[points->p[i].assign] = 1;
    k = centers->num;
    for (i = 0; i < points->num; i++) {
        if (is_a_median[i]) {
            memcpy(centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
            centers->p[k].weight = points->p[i].weight;
            centerIDs[k] = i + offset;
            k++;
        }
    }
    centers->num = k;
    free(is_a_median);
}

void outcenterIDs(Points *centers, long *centerIDs, char *outfile) {
    FILE *fp = fopen(outfile, "w");
    if (fp == NULL) { fprintf(stderr, "error opening %s\n", outfile); exit(1); }
    int *is_a_median = (int*)calloc(sizeof(int), centers->num);
    for (int i = 0; i < centers->num; i++)
        is_a_median[centers->p[i].assign] = 1;
    for (int i = 0; i < centers->num; i++) {
        if (is_a_median[i]) {
            fprintf(fp, "%u\n",  centerIDs[i]);
            fprintf(fp, "%lf\n", centers->p[i].weight);
            for (int k = 0; k < centers->dim; k++)
                fprintf(fp, "%lf ", centers->p[i].coord[k]);
            fprintf(fp, "\n\n");
        }
    }
    fclose(fp);
}

// -----------------------------------------------------------------------
// localSearch
// -----------------------------------------------------------------------
struct pkmedian_arg_t {
    Points *points;
    long    kmin;
    long    kmax;
    long   *kfinal;
    int     pid;
    pthread_barrier_t *barrier;
};

void *localSearchSub(void *arg_) {
    pkmedian_arg_t *arg = (pkmedian_arg_t*)arg_;
    pkmedian(arg->points, arg->kmin, arg->kmax, arg->kfinal, arg->pid, arg->barrier);
    return NULL;
}

void localSearch(Points *points, long kmin, long kmax, long *kfinal) {
#ifdef PROFILE
    double t1 = gettime();
#endif
    pthread_barrier_t barrier;
    pkmedian_arg_t arg;
    arg.points = points;
    arg.kmin   = kmin;
    arg.kmax   = kmax;
    arg.pid    = 0;
    arg.kfinal = kfinal;
    arg.barrier = &barrier;
    localSearchSub(&arg);
#ifdef PROFILE
    double t2 = gettime();
    time_local_search += t2-t1;
#endif
}

// -----------------------------------------------------------------------
// streamCluster
// -----------------------------------------------------------------------
void streamCluster(PStream *stream, long kmin, long kmax, int dim,
                   long chunksize, long centersize, char *outfile) {
    block = (float*)malloc(chunksize*dim*sizeof(float));
    float *centerBlock = (float*)malloc(centersize*dim*sizeof(float));
    long  *centerIDs   = (long* )malloc(centersize*dim*sizeof(long));

    if (block == NULL) { fprintf(stderr,"not enough memory for a chunk!\n"); exit(1); }

    Points points;
    points.dim = dim;
    points.num = chunksize;
    points.p   = (Point *)malloc(chunksize*sizeof(Point));
    for (int i = 0; i < chunksize; i++)
        points.p[i].coord = &block[i*dim];

    Points centers;
    centers.dim = dim;
    centers.p   = (Point *)malloc(centersize*sizeof(Point));
    centers.num = 0;
    for (int i = 0; i < centersize; i++) {
        centers.p[i].coord  = &centerBlock[i*dim];
        centers.p[i].weight = 1.0f;
    }

    long IDoffset = 0;
    long kfinal;

    while (1) {
        size_t numRead = stream->read(block, dim, chunksize);
        fprintf(stderr, "read %d points\n", (int)numRead);

        if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
            fprintf(stderr, "error reading data!\n");
            exit(1);
        }

        points.num = numRead;
        for (int i = 0; i < points.num; i++)
            points.p[i].weight = 1.0f;

        switch_membership = (bool*)malloc(points.num*sizeof(bool));
        is_center         = (bool*)calloc(points.num, sizeof(bool));
        center_table      = (int* )malloc(points.num*sizeof(int));

        localSearch(&points, kmin, kmax, &kfinal);
        fprintf(stderr, "finish local search\n");

        contcenters(&points);
        if (kfinal + centers.num > centersize) {
            fprintf(stderr, "oops! no more space for centers\n");
            exit(1);
        }

        copycenters(&points, &centers, centerIDs, IDoffset);
        IDoffset += numRead;

        free(is_center);
        free(switch_membership);
        free(center_table);

        if (stream->feof()) break;
    }

    switch_membership = (bool*)malloc(centers.num*sizeof(bool));
    is_center         = (bool*)calloc(centers.num, sizeof(bool));
    center_table      = (int* )malloc(centers.num*sizeof(int));

    localSearch(&centers, kmin, kmax, &kfinal);
    contcenters(&centers);
    outcenterIDs(&centers, centerIDs, outfile);

    // Free persistent device memory
    if (d_coord)             { cudaFree(d_coord);             d_coord             = NULL; }
    if (d_center_table)      { cudaFree(d_center_table);      d_center_table      = NULL; }
    if (d_switch_membership) { cudaFree(d_switch_membership); d_switch_membership = NULL; }
    if (d_is_center)         { cudaFree(d_is_center);         d_is_center         = NULL; }
    if (d_p_cost)            { cudaFree(d_p_cost);            d_p_cost            = NULL; }
    if (d_p_weight)          { cudaFree(d_p_weight);          d_p_weight          = NULL; }
    if (d_p_assign)          { cudaFree(d_p_assign);          d_p_assign          = NULL; }
    d_num_allocated = 0;
    d_dim_allocated = 0;
}

// -----------------------------------------------------------------------
// main
// -----------------------------------------------------------------------
int main(int argc, char **argv) {
    char *outfilename = new char[MAXNAMESIZE];
    char *infilename  = new char[MAXNAMESIZE];
    long kmin, kmax, n, chunksize, clustersize;
    int  dim;
    c = 0; d = 0;

    printf("PARSEC Benchmark Suite\n");
    fflush(NULL);

    if (argc < 10) {
        fprintf(stderr,"usage: %s k1 k2 d n chunksize clustersize infile outfile nproc\n", argv[0]);
        fprintf(stderr,"  k1:          Min. number of centers allowed\n");
        fprintf(stderr,"  k2:          Max. number of centers allowed\n");
        fprintf(stderr,"  d:           Dimension of each data point\n");
        fprintf(stderr,"  n:           Number of data points\n");
        fprintf(stderr,"  chunksize:   Number of data points to handle per step\n");
        fprintf(stderr,"  clustersize: Maximum number of intermediate centers\n");
        fprintf(stderr,"  infile:      Input file (if n<=0)\n");
        fprintf(stderr,"  outfile:     Output file\n");
        fprintf(stderr,"  nproc:       Number of threads to use\n");
        fprintf(stderr,"\n");
        fprintf(stderr,"if n > 0, points will be randomly generated instead of reading from infile.\n");
        exit(1);
    }

    kmin        = atoi(argv[1]);
    kmax        = atoi(argv[2]);
    dim         = atoi(argv[3]);
    n           = atoi(argv[4]);
    chunksize   = atoi(argv[5]);
    clustersize = atoi(argv[6]);
    strcpy(infilename,  argv[7]);
    strcpy(outfilename, argv[8]);
    nproc = atoi(argv[9]);
    nproc = 1;   // GPU handles parallelism

    srand48(SEED);
    PStream *stream;
    if (n > 0) stream = new SimStream(n);
    else       stream = new FileStream(infilename);

    double t1 = gettime();
    streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename);
    double t2 = gettime();

    printf("time = %lf\n", t2-t1);
    delete stream;

    printf("time pgain = %lf\n",       time_gain);
    printf("time pgain_dist = %lf\n",  time_gain_dist);
    printf("time pgain_init = %lf\n",  time_gain_init);
    printf("time pselect = %lf\n",     time_select_feasible);
    printf("time pspeedy = %lf\n",     time_speedy);
    printf("time pshuffle = %lf\n",    time_shuffle);
    printf("time localSearch = %lf\n", time_local_search);
    printf("loops=%d\n", d);

    return 0;
}

